/* WAM Runtime Header - Generated by UnifyWeaver */
#ifndef WAM_RUNTIME_H
#define WAM_RUNTIME_H

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>
#include <assert.h>

#define WAM_HALT -1
#define WAM_MAX_REGS 256
#define WAM_INITIAL_CAP 64

/* Value tag enum */
typedef enum {
    VAL_ATOM, VAL_INT, VAL_REF, VAL_STR, VAL_UNBOUND, VAL_LIST
} WamValueTag;

typedef struct {
    WamValueTag tag;
    union {
        const char *atom;
        int integer;
        int ref_addr;
        const char *str_functor;
        const char *unbound_name;
    } data;
} WamValue;

/* Trail entry */
typedef struct {
    WamValue *cell;
    WamValue old_val;
} TrailEntry;

/* Choice point */
typedef struct {
    int next_pc;
    int cp;
    int heap_size;
    int trail_size;
    int stack_size;
    int arity;
    WamValue a_regs[32]; // Reduced from MAX_REGS to save memory (typical max arity)
} ChoicePoint;

/* Environment Frame */
typedef struct {
    int cp;
    int saved_e;
    WamValue y_regs[32];
} EnvFrame;

/* Instruction tags */
typedef enum {
    INSTR_GET_CONSTANT, INSTR_GET_VARIABLE, INSTR_GET_VALUE,
    INSTR_GET_STRUCTURE, INSTR_GET_LIST,
    INSTR_PUT_CONSTANT, INSTR_PUT_VARIABLE, INSTR_PUT_VALUE,
    INSTR_PUT_STRUCTURE, INSTR_PUT_LIST,
    INSTR_SET_VARIABLE, INSTR_SET_VALUE, INSTR_SET_CONSTANT,
    INSTR_UNIFY_VARIABLE, INSTR_UNIFY_VALUE, INSTR_UNIFY_CONSTANT,
    INSTR_CALL, INSTR_EXECUTE, INSTR_PROCEED,
    INSTR_ALLOCATE, INSTR_DEALLOCATE,
    INSTR_TRY_ME_ELSE, INSTR_RETRY_ME_ELSE, INSTR_TRUST_ME,
    INSTR_SWITCH_ON_CONSTANT, INSTR_BUILTIN_CALL
} WamInstrTag;

/* Instruction */
// TODO: Pack these fields into a union keyed on `tag` to reduce memory footprint
typedef struct {
    WamInstrTag tag;
    int reg;
    int is_y_reg;
    int reg_xn;
    int is_y_xn;
    int reg_ai;
    int is_y_ai;
    WamValue val;
    int arity;
    char *pred;
    char *label;
} Instruction;

/* WAM state */
typedef struct {
    int P;    // Program Counter
    int CP;   // Continuation Pointer
    int S;    // Structure Pointer
    int HB;   // Heap Backtrack Pointer
    
    /* Registers: A and X registers share the same space typically */
    WamValue A[WAM_MAX_REGS];
    WamValue X[WAM_MAX_REGS];
    
    /* Heap */
    WamValue *H_array;
    int H;    // Heap size/pointer
    int H_cap;
    
    /* Trail */
    TrailEntry *TR_array;
    int TR;   // Trail size/pointer
    int TR_cap;
    
    /* Choice points */
    ChoicePoint *B_array;
    int B;    // Choice point size/pointer
    int B_cap;
    
    /* Stack (Environments) */
    EnvFrame *E_array;
    int E;    // Stack size/pointer
    int E_cap;
    
    /* Code */
    Instruction *code;
    int code_size;
    
    /* Labels */
    char **label_names;
    int *label_pcs;
    int label_count;
    int label_cap;
} WamState;

/* Helpers */
static inline WamValue val_atom(const char *s) {
    // We avoid strdup here to prevent leaks, assuming 's' is a string literal.
    // Dynamic atoms will require an interning table later.
    WamValue v; v.tag = VAL_ATOM; v.data.atom = s; return v;
}
static inline WamValue val_int(int n) {
    WamValue v; v.tag = VAL_INT; v.data.integer = n; return v;
}
static inline WamValue val_unbound(const char *name) {
    WamValue v; v.tag = VAL_UNBOUND; v.data.unbound_name = name; return v;
}
static inline WamValue wam_make_ref(WamState *state) {
    if (state->H >= state->H_cap) {
        state->H_cap = state->H_cap ? state->H_cap * 2 : WAM_INITIAL_CAP;
        state->H_array = realloc(state->H_array, sizeof(WamValue) * state->H_cap);
    }
    WamValue ref;
    ref.tag = VAL_REF;
    ref.data.ref_addr = state->H;
    state->H_array[state->H] = val_unbound("heap_var");
    state->H++;
    return ref;
}
static inline bool val_is_unbound(WamValue v) {
    return v.tag == VAL_UNBOUND;
}
static inline bool val_equal(WamValue v1, WamValue v2) {
    if (v1.tag != v2.tag) return false;
    if (v1.tag == VAL_INT) return v1.data.integer == v2.data.integer;
    if (v1.tag == VAL_ATOM) return strcmp(v1.data.atom, v2.data.atom) == 0;
    // simplify for demonstration
    return false;
}
static inline WamValue* resolve_reg(WamState *state, int reg_idx, int is_y) {
    if (is_y) {
        assert(state->E >= 0 && "Y-register accessed with empty environment stack");
        return &state->E_array[state->E].y_regs[reg_idx];
    }
    return &state->A[reg_idx];
}
static inline void trail_binding(WamState *state, WamValue *cell) {
    if (state->TR >= state->TR_cap) {
        state->TR_cap = state->TR_cap ? state->TR_cap * 2 : WAM_INITIAL_CAP;
        state->TR_array = realloc(state->TR_array, sizeof(TrailEntry) * state->TR_cap);
    }
    state->TR_array[state->TR].cell = cell;
    state->TR_array[state->TR].old_val = *cell;
    state->TR++;
}
static inline void push_choice_point(WamState *state, int next_pc, int arity) {
    if (state->B >= state->B_cap) {
        state->B_cap = state->B_cap ? state->B_cap * 2 : WAM_INITIAL_CAP;
        state->B_array = realloc(state->B_array, sizeof(ChoicePoint) * state->B_cap);
    }
    ChoicePoint *cp = &state->B_array[state->B];
    cp->next_pc = next_pc;
    cp->cp = state->CP;
    cp->heap_size = state->H;
    cp->trail_size = state->TR;
    cp->stack_size = state->E;
    
    int save_arity = arity < 32 ? arity : 32;
    cp->arity = save_arity;
    memcpy(cp->a_regs, state->A, sizeof(WamValue) * save_arity);
    state->B++;
    state->HB = state->H;
}
static inline void unwind_trail(WamState *state, int target_tr) {
    while (state->TR > target_tr) {
        state->TR--;
        TrailEntry *te = &state->TR_array[state->TR];
        *te->cell = te->old_val;
    }
}
static inline void restore_choice_point(WamState *state, ChoicePoint *cp) {
    state->H = cp->heap_size;
    state->E = cp->stack_size;
    state->CP = cp->cp;
    unwind_trail(state, cp->trail_size);
    memcpy(state->A, cp->a_regs, sizeof(WamValue) * cp->arity);
}
static inline void pop_choice_point(WamState *state) {
    if (state->B > 0) {
        state->B--;
        if (state->B > 0) {
            state->HB = state->B_array[state->B - 1].heap_size;
        } else {
            state->HB = 0;
        }
    }
}
static inline void update_choice_point(WamState *state, int next_pc) {
    if (state->B > 0) {
        state->B_array[state->B - 1].next_pc = next_pc;
    }
}
static inline int resolve_label(WamState *state, const char *label) {
    // TODO: Optimize from O(n) to O(1) or O(log n) via hash map or bsearch
    for (int i = 0; i < state->label_count; i++) {
        if (strcmp(state->label_names[i], label) == 0) return state->label_pcs[i];
    }
    return -1;
}

#endif /* WAM_RUNTIME_H */
